import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { LayoutComponent } from './shared/layout.component';

const ORGANIZER = { roles: ['organizer'] as const };

/**
 * GatherUp route tree. Hash routing is configured in app.config.ts.
 * Login/signup render standalone; everything else is wrapped by LayoutComponent.
 * Public browse routes live inside the layout WITHOUT a guard. Each route
 * carries `data.flow { node, edgesTo, ... }` for the flow map.
 */
export const routes: Routes = [
  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { node: 'login', entry: true, edgesTo: ['home', 'signup', 'organizer'] } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { node: 'signup', edgesTo: ['home', 'login'] } },
  },
  {
    path: '',
    component: LayoutComponent,
    children: [
      // ---- Public browse ----
      {
        path: '',
        pathMatch: 'full',
        loadComponent: () => import('./pages/home/home.component').then((m) => m.HomeComponent),
        data: { flow: { node: 'home', showInNavbar: true, edgesTo: ['events', 'event-detail', 'my-events'] } },
      },
      {
        path: 'events',
        loadComponent: () =>
          import('./pages/events-list/events-list.component').then((m) => m.EventsListComponent),
        data: { flow: { node: 'events', showInNavbar: true, edgesTo: ['event-detail', 'home'] } },
      },
      {
        path: 'events/:id',
        loadComponent: () =>
          import('./pages/event-detail/event-detail.component').then((m) => m.EventDetailComponent),
        data: { flow: { node: 'event-detail', edgesTo: ['events', 'login', 'my-events'] } },
      },

      // ---- Attendee (any logged-in user) ----
      {
        path: 'my-events',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/my-events/my-events.component').then((m) => m.MyEventsComponent),
        data: { flow: { node: 'my-events', showInNavbar: true, scope: 'attendee', edgesTo: ['event-detail', 'events'] } },
      },

      // ---- Organizer ----
      {
        path: 'organizer',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/organizer-dashboard/organizer-dashboard.component').then(
            (m) => m.OrganizerDashboardComponent,
          ),
        data: { roles: ORGANIZER.roles, flow: { node: 'organizer', showInNavbar: true, scope: 'organizer', edgesTo: ['organizer-event-attendees', 'venues'] } },
      },
      {
        path: 'organizer/events/:id',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/organizer-event-attendees/organizer-event-attendees.component').then(
            (m) => m.OrganizerEventAttendeesComponent,
          ),
        data: { roles: ORGANIZER.roles, flow: { node: 'organizer-event-attendees', scope: 'organizer', edgesTo: ['organizer'] } },
      },
      {
        path: 'organizer/venues',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/venues-list/venues-list.component').then((m) => m.VenuesListComponent),
        data: { roles: ORGANIZER.roles, flow: { node: 'venues', showInNavbar: true, scope: 'organizer', edgesTo: ['venue-form'] } },
      },
      {
        path: 'organizer/venues/new',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/venue-form/venue-form.component').then((m) => m.VenueFormComponent),
        data: { roles: ORGANIZER.roles, flow: { node: 'venue-form', scope: 'organizer', edgesTo: ['venues'] } },
      },
      {
        path: 'organizer/venues/:id',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/venue-form/venue-form.component').then((m) => m.VenueFormComponent),
        data: { roles: ORGANIZER.roles, flow: { node: 'venue-form', scope: 'organizer', edgesTo: ['venues'] } },
      },
      {
        path: 'organizer/settings',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-settings/admin-settings.component').then(
            (m) => m.AdminSettingsComponent,
          ),
        data: { roles: ORGANIZER.roles, flow: { node: 'admin-settings', showInNavbar: true, scope: 'organizer', edgesTo: ['organizer'] } },
      },
    ],
  },

  { path: '**', redirectTo: '' },
];
