import { Component, OnInit, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, RouterLinkActive, RouterOutlet } from '@angular/router';
import { AuthService } from '../core/services/auth.service';

interface NavItem {
  label: string;
  icon: string;
  link: string;
  /** 'public' = always, 'auth' = any logged-in user, 'organizer' = organizers only. */
  scope: 'public' | 'auth' | 'organizer';
  exact?: boolean;
}

/**
 * GatherUp shell: brand header + top nav on desktop, a fixed bottom tab bar on
 * mobile (≤768px). Nav adapts to visitor / attendee / organizer.
 * SMOKE_MARKER: GatherUp
 */
@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterLinkActive, RouterOutlet],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css',
})
export class LayoutComponent implements OnInit {
  private readonly allNav: NavItem[] = [
    { label: 'Home', icon: '🏠', link: '/', scope: 'public', exact: true },
    { label: 'Events', icon: '🎟️', link: '/events', scope: 'public' },
    { label: 'My Events', icon: '⭐', link: '/my-events', scope: 'auth' },
    { label: 'Organizer', icon: '📋', link: '/organizer', scope: 'organizer', exact: true },
    { label: 'Venues', icon: '📍', link: '/organizer/venues', scope: 'organizer' },
    { label: 'Settings', icon: '⚙️', link: '/organizer/settings', scope: 'organizer' },
  ];

  readonly nav = computed<NavItem[]>(() => {
    const loggedIn = this.auth.isLoggedIn();
    const organizer = this.auth.isOrganizer();
    return this.allNav.filter((n) => {
      if (n.scope === 'public') return true;
      if (n.scope === 'auth') return loggedIn;
      return organizer;
    });
  });

  // Bottom-tab nav shows at most 5 primary items on mobile.
  readonly bottomNav = computed<NavItem[]>(() => this.nav().slice(0, 5));

  readonly userName = computed(
    () => this.auth.user()?.name || this.auth.user()?.email || 'Account',
  );
  readonly roleLabel = computed(() => (this.auth.isOrganizer() ? 'Organizer' : 'Attendee'));

  constructor(public auth: AuthService) {}

  ngOnInit(): void {
    // Hydrate the header/nav from the live authenticated user (GET /users/me).
    // Errors keep the cached user (e.g. demo mode) — no redirect here.
    if (this.auth.isLoggedIn()) {
      this.auth.refresh().subscribe({ error: () => {} });
    }
  }

  logout(): void {
    this.auth.logout();
  }
}
